Structure cache keys as `tenant:{tid}:user:{uid}:profile` with TTL 3600s. Publish invalidation messages on `invalidate:tenant:{tid}:profile` channel when profiles update. On cache miss, reload from database and repopulate cache. Implement distributed locks using Redis SETNX with 30s TTL to prevent stampede during cache rebuilds. Ensure idempotent invalidation by checking message processing status.

**Flow**: Update profile → Publish to invalidation channel → Subscribers clear affected keys → Next request triggers controlled cache reload with lock protection.

**Code snippet**:
```javascript
async function getProfile(tenantId, userId) {
  const key = `tenant:${tenantId}:user:${userId}:profile`;
  const lockKey = `${key}:lock`;

  let data = await redis.get(key);
  if (data) return JSON.parse(data);

  // Stampede protection
  const lockAcquired = await redis.set(lockKey, '1', 'PX', 30000, 'NX');
  if (!lockAcquired) {
    // Wait and retry if lock not acquired
    await new Promise(resolve => setTimeout(resolve, 100));
    return getProfile(tenantId, userId);
  }

  try {
    const profile = await db.getProfile(tenantId, userId);
    await redis.setex(key, 3600, JSON.stringify(profile));
    return profile;
  } finally {
    await redis.del(lockKey);
  }
}

// Invalidate on update
async function updateProfile(tenantId, userId, updates) {
  await db.updateProfile(tenantId, userId, updates);
  const key = `tenant:${tenantId}:user:${userId}:profile`;
  await redis.del(key);
  await redis.publish(`invalidate:tenant:${tenantId}:profile`, userId);
}
```

